import{_ as s,c as a,o as l,a as n}from"./app.6cebd806.js";const o="/yubi-blog/assets/wujie01.fcde41cf.webp",u=JSON.parse('{"title":"微前端初探","description":"","frontmatter":{},"headers":[{"level":2,"title":"一个较为完备的微前端框架应该具备以下特征","slug":"一个较为完备的微前端框架应该具备以下特征","link":"#一个较为完备的微前端框架应该具备以下特征","children":[]},{"level":2,"title":"常见的微前端框架","slug":"常见的微前端框架","link":"#常见的微前端框架","children":[{"level":3,"title":"iframe","slug":"iframe","link":"#iframe","children":[]},{"level":3,"title":"singleSpa和乾坤","slug":"singlespa和乾坤","link":"#singlespa和乾坤","children":[]},{"level":3,"title":"mircoApp","slug":"mircoapp","link":"#mircoapp","children":[]}]},{"level":2,"title":"无界","slug":"无界","link":"#无界","children":[]}],"relativePath":"docs/前端工程化相关/微前端/微前端初探.md","lastUpdated":1677691058000}'),e={name:"docs/前端工程化相关/微前端/微前端初探.md"},p=n(`<h1 id="微前端初探" tabindex="-1">微前端初探 <a class="header-anchor" href="#微前端初探" aria-hidden="true">#</a></h1><blockquote><p>微前端的概念是由ThoughtWorks在2016年提出的，它借鉴了微服务的架构理念，核心在于将一个庞大的前端应用拆分成多个独立灵活的小型应用，每个应用都可以独立开发、独立运行、独立部署，再将这些小型应用融合为一个完整的应用，或者将原本运行已久、没有关联的几个应用融合为一个应用。微前端既可以将多个项目融合为一，又可以减少项目之间的耦合，提升项目扩展性，相比一整块的前端仓库，微前端架构下的前端仓库倾向于更小更灵活。</p></blockquote><p>他（部分）解决了以下问题：</p><ol><li>随着项目迭代应用越来越庞大，难以维护。</li><li>跨团队或跨部门协作开发项目导致效率低下的问题。</li><li>不同团队的技术栈差异问题。</li><li>降低项目迭代过程中的技术栈升级或者重构成本，可达到渐进式重构的效果。</li></ol><h2 id="一个较为完备的微前端框架应该具备以下特征" tabindex="-1">一个较为完备的微前端框架应该具备以下特征 <a class="header-anchor" href="#一个较为完备的微前端框架应该具备以下特征" aria-hidden="true">#</a></h2><blockquote><p>这是随着几个微前端框架的迭代慢慢确立下来的，根据痛点进行优化。</p></blockquote><ol><li>js隔离（状态隔离）</li><li>样式隔离</li><li>通讯系统</li><li>预加载能力</li><li>生命周期系统</li><li>微应用路由处理</li><li>应用保活</li></ol><h2 id="常见的微前端框架" tabindex="-1">常见的微前端框架 <a class="header-anchor" href="#常见的微前端框架" aria-hidden="true">#</a></h2><h3 id="iframe" tabindex="-1">iframe <a class="header-anchor" href="#iframe" aria-hidden="true">#</a></h3><blockquote><p>iframe是一个残缺且卓越的微前端解决方案</p></blockquote><ol><li>完美的隔离，无论是js还是css</li><li>微应用url不同步，后退前进不可以。</li><li>每次打开微应用都是重新加载，不具备保活能力。</li></ol><h3 id="singlespa和乾坤" tabindex="-1">singleSpa和乾坤 <a class="header-anchor" href="#singlespa和乾坤" aria-hidden="true">#</a></h3><blockquote><p>乾坤是基于singleSpa封装的，由此带来一系列问题，例如对微应用的入侵。</p><p>即，微应用需要在自己的入口 js (通常就是你配置的 webpack 的 entry js) 导出 bootstrap、mount、unmount 三个生命周期钩子，以供主应用在适当的时机调用。</p></blockquote><ol><li>乾坤具有完善的沙箱方案。js的SnapshotSandbox、LegacySandbox、ProxySandbox，css的strictStyleIsolation、experimentalStyleIsolation。适合不同场景使用不同的方案。</li><li>路由保持，浏览器刷新、前进、后退，都可以作用到子应用。</li><li>在qiankun2.x版本中，也使用了shadow DOM进行css隔离</li></ol><h3 id="mircoapp" tabindex="-1">mircoApp <a class="header-anchor" href="#mircoapp" aria-hidden="true">#</a></h3><blockquote><p>来自京东团队的微前端框架是一款基于类web component组件</p></blockquote><ol><li>js沙箱，用<code>Proxy</code>拦截了用户全局操作行为，防止对window的访问。（但也提供了访问window的方法，不过并不友好）</li></ol><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki"><code><span class="line"><span style="color:#676E95;">// 三种方法</span></span>
<span class="line"><span style="color:#89DDFF;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">Function</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">return window</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">)() 或 </span><span style="color:#82AAFF;">Function</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">return window</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">)()</span></span>
<span class="line"><span style="color:#A6ACCD;">(</span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> eval)(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">window</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"><span style="color:#A6ACCD;">window</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">rawWindow</span></span>
<span class="line"></span></code></pre></div><ol start="2"><li>用Shadow Dom或babel插件对样式转换来限制作用域。（简单来说是给所有样式加前缀）但是会受到基座应用的污染。</li></ol><blockquote><p>shadow Dom是可开启的，具有更好的隔离性，但文档里面提醒了“一些框架(如React)对shadowDOM的兼容性不好，请谨慎使用。”</p><p>开启shadowDOM后，默认的样式隔离将失效。</p></blockquote><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki"><code><span class="line"><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">test</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#B2CCD6;">color</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> red</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;">/* 转换为 */</span></span>
<span class="line"><span style="color:#FFCB6B;">micro-app</span><span style="color:#89DDFF;">[</span><span style="color:#C792EA;">name</span><span style="color:#89DDFF;">=</span><span style="color:#C3E88D;">xxx</span><span style="color:#89DDFF;">]</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">test</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#B2CCD6;">color</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> red</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><ol start="3"><li>元素隔离。对元素边界进行限制。</li></ol><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki"><code><span class="line"><span style="color:#676E95;">// 简单来说 微应用和基座应用都有id为root的元素</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">root</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">&gt;&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;">// 此时子应用通过querySelector只会查询到子应用的id</span></span>
<span class="line"><span style="color:#A6ACCD;">document</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">querySelector</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">#root</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"></span></code></pre></div><ol start="4"><li>支持预加载</li></ol><blockquote><p>预加载并不是同步执行的，它会在浏览器空闲时间，依照开发者传入的顺序，依次加载每个应用的静态资源，以确保不会影响基座应用的性能。</p></blockquote><h2 id="无界" tabindex="-1">无界 <a class="header-anchor" href="#无界" aria-hidden="true">#</a></h2><blockquote><p>无界是腾讯PCG的微前端方案，是iframe为基础的微前端方案,推荐一篇相关的文章。<a href="https://zhuanlan.zhihu.com/p/442815952" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/p/442815952</a></p></blockquote><p>无界的优势是，解决iframe方案的缺点。</p><ul><li>dom割裂严重的问题，主应用提供一个容器给到shadowRoot插拔，shadowRoot内部的弹窗也就可以覆盖到整个应用A</li><li>路由状态丢失的问题，浏览器的前进后退可以天然的作用到iframe上，此时监听iframe的路由变化并同步到主应用，如果刷新浏览器，就可以从url读回保存的路由</li><li>通信非常困难的问题，iframe和主应用是同域的，天然的共享内存通信，而且无界提供了一个去中心化的事件机制</li><li>iframe加载的性能问题，<code>wujie</code>是通过提前实例化和保存<code>shadowRoot</code>来实现的。</li></ul><p><img src="`+o+'" alt=""></p>',30),t=[p];function c(r,i,d,D,y,F){return l(),a("div",null,t)}const C=s(e,[["render",c]]);export{u as __pageData,C as default};
